using System;
using System.Reflection;
using Microsoft.VisualStudio.TestTools.UnitTesting;

var assertType = typeof(Assert);
var methods = assertType.GetMethods(BindingFlags.Public | BindingFlags.Static);

foreach (var m in methods)
{
    if (m.Name == "AreEqual" || m.Name == "AreNotEqual" || m.Name == "AreSame")
