cat > /tmp/ReflectAssert.cs << 'EOF'
using System;
using System.Reflection;
using Microsoft.VisualStudio.TestTools.UnitTesting;

var assertType = typeof(Assert);
var methods = assertType.GetMethods(BindingFlags.Public | BindingFlags.Static);

foreach (var m in methods.OrderBy(m => m.Name).ThenBy(m => m.GetParameters().Length))
{
    if (m.Name == "AreEqual" || m.Name == "AreNotEqual" || m.Name == "AreSame" || m.Name == "AreNotSame")
    {
        var parms = string.Join(", ", Array.ConvertAll(m.GetParameters(), p => {
            var typeName = p.ParameterType.IsGenericParameter ? p.ParameterType.Name : p.ParameterType.FullName ?? p.ParameterType.Name;
            return $"{typeName} {p.Name}";
        }));
        var generic = m.IsGenericMethod ? $"<{string.Join(",", Array.ConvertAll(m.GetGenericArguments(), t => t.Name))}>" : "";

        var obsolete = m.GetCustomAttribute<ObsoleteAttribute>();
        var obsoleteStr = obsolete != null ? $" [OBSOLETE: {obsolete.Message}]" : "";
        var isError = obsolete?.IsError == true ? " (ERROR)" : "";

        Console.WriteLine($"{m.Name}{generic}({parms}){obsoleteStr}{isError}");
    }
}
EOF

